def _shanten_from_counts(counts: List[int], melds: int = 0) -> int:
    """Core shanten computation from count array."""
    needed_sets = 4 - melds
    best = 8

    # Standard: enumerate pair candidates
    for pair_idx in range(34):
        if counts[pair_idx] < 2:
            continue
        counts[pair_idx] -= 2

        sets_ = melds
        cc = list(counts)
        # Triplets
        for i in range(34):
            if cc[i] >= 3:
                sets_ += cc[i] // 3
                cc[i] %= 3
        # Sequences
        for i in range(27):
            se = (i // 9) * 9 + 9
            while i + 2 < se and cc[i] >= 1 and cc[i+1] >= 1 and cc[i+2] >= 1:
                sets_ += 1; cc[i] -= 1; cc[i+1] -= 1; cc[i+2] -= 1
        # Partial sets
        partials = 0
        for i in range(34):
            while cc[i] >= 2:
                partials += 1; cc[i] -= 2
        for i in range(27):
            se = (i // 9) * 9 + 9
            if i + 1 < se and cc[i] >= 1 and cc[i+1] >= 1:
                partials += 1; cc[i] -= 1; cc[i+1] -= 1
            elif i + 2 < se and cc[i] >= 1 and cc[i+2] >= 1:
                partials += 1; cc[i] -= 1; cc[i+2] -= 1

        effective = min(sets_ + partials, needed_sets)
        s = needed_sets - effective
        if s < best:
            best = s

        counts[pair_idx] += 2

    # Seven pairs
    pairs_count = sum(1 for c in counts if c >= 2)
    seven_s = max(0, 6 - pairs_count)
    if seven_s < best:
        best = seven_s

    return best - 1


